   151→/**
   152→ * General registry for implementation factories. The registry is templated by the Base class that a
   153→ * set of factories conforms to.
   154→ *
   155→ * Classes are found by name, so a single name cannot be registered twice for the same Base class.
   156→ * Factories are registered by reference and this reference is expected to be valid through the life
   157→ * of the program. Factories cannot be deregistered.
   158→ * Factories should generally be registered by statically instantiating the RegisterFactory class.
   159→ *
   160→ * Note: This class is not thread safe, so registration should only occur in a single threaded
   161→ * environment, which is guaranteed by the static instantiation mentioned above.
   162→ *
   163→ * Example lookup: BaseFactoryType *factory =
   164→ * FactoryRegistry<BaseFactoryType>::getFactory("example_factory_name");
   165→ */
   166→template <class Base> class FactoryRegistry : public Logger::Loggable<Logger::Id::config> {
   167→public:
   168→  /**
   169→   * Return a sorted vector of registered factory names.
   170→   */
   171→  static std::vector<absl::string_view> registeredNames(bool include_disabled = false) {
   172→    std::vector<absl::string_view> ret;
   173→
   174→    ret.reserve(factories().size());
   175→
   176→    for (const auto& [factory_name, factory] : factories()) {
   177→      if (factory || include_disabled) {
   178→        ret.push_back(factory_name);
   179→      }
   180→    }
   181→
   182→    std::sort(ret.begin(), ret.end());
   183→
   184→    return ret;
   185→  }
   186→
   187→  /**
   188→   * Gets the current map of factory implementations.
   189→   */
   190→  static absl::flat_hash_map<std::string, Base*>& factories() {
   191→    static auto* factories = new absl::flat_hash_map<std::string, Base*>;
   192→    return *factories;
   193→  }
   194→
   195→  /**
   196→   * Gets the current map of vendor specific factory versions.
   197→   */
   198→  static absl::flat_hash_map<std::string, envoy::config::core::v3::BuildVersion>&
   199→  versionedFactories() {
   200→    using VersionedFactoryMap =
   201→        absl::flat_hash_map<std::string, envoy::config::core::v3::BuildVersion>;
   202→    MUTABLE_CONSTRUCT_ON_FIRST_USE(VersionedFactoryMap);
   203→  }
   204→
   205→  static absl::flat_hash_map<std::string, std::string>& deprecatedFactoryNames() {
   206→    static auto* deprecated_factory_names = new absl::flat_hash_map<std::string, std::string>;
   207→    return *deprecated_factory_names;
   208→  }
   209→
   210→  /**
   211→   * Lazily constructs a mapping from the configuration message type to a factory,
   212→   * including the deprecated configuration message types.
   213→   * Must be invoked after factory registration is completed.
   214→   */
   215→  static absl::flat_hash_map<std::string, Base*>& factoriesByType() {
   216→    static absl::flat_hash_map<std::string, Base*>* factories_by_type =
   217→        buildFactoriesByType().release();
   218→
   219→    return *factories_by_type;
   220→  }
   221→
   222→  static bool& allowDuplicates() {
   223→    static bool* allow_duplicates = new bool(false);
   224→    return *allow_duplicates;
   225→  }
   226→
   227→  /**
   228→   * instead_value are used when passed name was deprecated.
   229→   */
   230→  static void registerFactory(Base& factory, absl::string_view name,
   231→                              absl::string_view instead_value = "") {
   232→    auto result = factories().emplace(std::make_pair(name, &factory));
   233→    if (!result.second && !allowDuplicates()) {
   234→      ExceptionUtil::throwEnvoyException(
   235→          fmt::format("Double registration for name: '{}'", factory.name()));
   236→    }
   237→
   238→    if (!instead_value.empty()) {
   239→      deprecatedFactoryNames().emplace(std::make_pair(name, instead_value));
   240→    }
   241→  }
   242→
   243→  /**
   244→   * version is used for registering vendor specific factories that are versioned
   245→   * independently of Envoy.
   246→   */
   247→  static void registerFactory(Base& factory, absl::string_view name,
   248→                              const envoy::config::core::v3::BuildVersion& version,
   249→                              absl::string_view instead_value = "") {
   250→    auto result = factories().emplace(std::make_pair(name, &factory));
   251→    if (!result.second) {
   252→      ExceptionUtil::throwEnvoyException(
   253→          fmt::format("Double registration for name: '{}'", factory.name()));
   254→    }
   255→    versionedFactories().emplace(std::make_pair(name, version));
   256→    if (!instead_value.empty()) {
   257→      deprecatedFactoryNames().emplace(std::make_pair(name, instead_value));
   258→    }
   259→  }
   260→
   261→  /**
   262→   * Permanently disables the named factory by setting the corresponding
   263→   * factory pointer to null. If the factory is registered under multiple
   264→   * (deprecated) names, all the possible names are disabled.
   265→   */
   266→  static bool disableFactory(absl::string_view name) {
   267→    const auto disable = [](absl::string_view name) -> bool {
   268→      auto it = factories().find(name);
   269→      if (it != factories().end()) {
   270→        it->second = nullptr;
   271→        return true;
   272→      }
   273→      return false;
   274→    };
   275→
   276→    // First, find the canonical name for this factory.
   277→    absl::string_view canonicalName = canonicalFactoryName(name);
   278→
   279→    // Next, disable the factory by all its deprecated names.
   280→    for (const auto& [deprecated_name, mapped_canonical_name] : deprecatedFactoryNames()) {
   281→      if (mapped_canonical_name == canonicalName) {
   282→        disable(deprecated_name);
   283→      }
   284→    }
   285→
   286→    // Finally, disable the factory by its canonical name.
   287→    return disable(canonicalName);
   288→  }
   289→
   290→  /**
   291→   * Gets a factory by name. If the name isn't found in the registry, returns nullptr.
   292→   */
   293→  static Base* getFactory(absl::string_view name) {
   294→    auto it = factories().find(name);
   295→    if (it == factories().end()) {
   296→      return nullptr;
   297→    }
   298→
   299→    return it->second;
   300→  }
   301→
   302→  static Base* getFactoryByType(absl::string_view type) {
   303→    auto it = factoriesByType().find(type);
   304→    if (it == factoriesByType().end()) {
   305→      return nullptr;
   306→    }
   307→    return it->second;
   308→  }
   309→
   310→  /**
   311→   * @return the canonical name of the factory. If the given name is a
   312→   * deprecated factory name, the canonical name is returned instead.
   313→   */
   314→  static absl::string_view canonicalFactoryName(absl::string_view name) {
   315→    const auto it = deprecatedFactoryNames().find(name);
   316→    return (it == deprecatedFactoryNames().end()) ? name : it->second;
   317→  }
   318→
   319→  /**
   320→   * @return true if the named factory was disabled.
   321→   */
   322→  static bool isFactoryDisabled(absl::string_view name) {
   323→    auto it = factories().find(name);
   324→    ASSERT(it != factories().end());
   325→    return it->second == nullptr;
   326→  }
   327→
   328→  /**
   329→   * @return vendor specific version of a factory.
   330→   */
   331→  static absl::optional<envoy::config::core::v3::BuildVersion>
   332→  getFactoryVersion(absl::string_view name) {
   333→    auto it = versionedFactories().find(name);
   334→    if (it == versionedFactories().end()) {
   335→      return absl::nullopt;
   336→    }
   337→    return it->second;
   338→  }
   339→
   340→  /**
   341→   * @return set of config type names indexed by the factory name.
   342→   */
   343→  static absl::flat_hash_map<std::string, std::vector<std::string>> registeredTypes() {
   344→    absl::flat_hash_map<std::string, std::vector<std::string>> mapping;
   345→    for (const auto& [config_type, factory] : factoriesByType()) {
   346→      mapping[factory->name()].push_back(config_type);
   347→    }
   348→    return mapping;
   349→  }
   350→
   351→private:
   352→  // Allow factory injection only in tests.
   353→  friend class InjectFactory<Base>;
   354→
   355→  static std::unique_ptr<absl::flat_hash_map<std::string, Base*>> buildFactoriesByType() {
   356→    auto mapping = std::make_unique<absl::flat_hash_map<std::string, Base*>>();
   357→
   358→    for (const auto& [factory_name, factory] : factories()) {
   359→      UNREFERENCED_PARAMETER(factory_name);
   360→      if (factory == nullptr) {
   361→        continue;
   362→      }
   363→
   364→      for (const auto& config_type : factory->configTypes()) {
   365→        ASSERT(!config_type.empty(), "Extension config types can never be empty string");
   366→
   367→        // Register config types in the mapping.
   368→        auto it = mapping->find(config_type);
   369→        if (it != mapping->end() && it->second != factory) {
   370→          // Mark double-registered types with a nullptr for tests only.
   371→          // See issue https://github.com/envoyproxy/envoy/issues/9643.
   372→          RELEASE_ASSERT(false, fmt::format("Double registration for type: '{}' by '{}' and '{}'",
   373→                                            config_type, factory->name(),
   374→                                            it->second ? it->second->name() : ""));
   375→          it->second = nullptr;
   376→        } else {
   377→          mapping->emplace(std::make_pair(config_type, factory));
   378→        }
   379→      }
   380→    }
   381→
   382→    return mapping;
   383→  }
   384→
   385→  // Rebuild the factories-by-type map based on the current factories.
   386→  static void rebuildFactoriesByTypeForTest() {
   387→    auto& mapping = factoriesByType();
   388→    auto updated_mapping = buildFactoriesByType();
   389→
   390→    // Copy the updated mapping over the old one.
   391→    mapping = *updated_mapping;
   392→  }
   393→
   394→  /**
   395→   * Replaces a factory by name. This method should only be used for testing purposes.
   396→   * @param factory is the factory to inject.
   397→   * @param deprecated_names install the given deprecated names for this factory.
   398→   * @return std::function<void()> a function that will restore the previously registered factories
   399→   *         (by name or type).
   400→   */
   401→  static std::function<void()>
   402→  replaceFactoryForTest(Base& factory,
   403→                        std::initializer_list<absl::string_view> deprecated_names = {}) {
   404→    using DeprecatedNamesVector = std::vector<std::pair<std::string, std::string>>;
   405→
   406→    // If an existing factory is registered with this name, track it for later restoration.
   407→    Base* prev_by_name = nullptr;
   408→    auto it = factories().find(factory.name());
   409→    if (it != factories().end()) {
   410→      prev_by_name = it->second;
   411→      factories().erase(it);
   412→
   413→      ENVOY_LOG(
   414→          info, "Factory '{}' (type '{}') displaced-by-name with test factory '{}' (type '{}')",
   415→          prev_by_name->name(), prev_by_name->configTypes(), factory.name(), factory.configTypes());
   416→    } else {
   417→      ENVOY_LOG(info, "Factory '{}' (type '{}') registered for tests", factory.name(),
   418→                factory.configTypes());
   419→    }
   420→
   421→    factories().emplace(factory.name(), &factory);
   422→    RELEASE_ASSERT(getFactory(factory.name()) == &factory,
   423→                   "test factory by-name registration failed");
   424→
   425→    DeprecatedNamesVector prev_deprecated_names;
   426→    if (deprecated_names.size() > 0) {
   427→      for (auto deprecated_name : deprecated_names) {
   428→        auto it = deprecatedFactoryNames().find(deprecated_name);
   429→        if (it != deprecatedFactoryNames().end()) {
   430→          prev_deprecated_names.emplace_back(std::make_pair(it->first, it->second));
   431→          deprecatedFactoryNames().erase(it);
   432→
   433→          ENVOY_LOG(
   434→              info,
   435→              "Deprecated name '{}' (mapped to '{}') displaced with test factory '{}' (type '{}')",
   436→              it->first, it->second, factory.name(), factory.configTypes());
   437→        } else {
   438→          // Name not previously mapped, remember to remove it.
   439→          prev_deprecated_names.emplace_back(std::make_pair(deprecated_name, ""));
   440→
   441→          ENVOY_LOG(info, "Deprecated name '{}' (mapped to '{}')", deprecated_name, factory.name());
   442→        }
   443→
   444→        // Register the replacement factory with a deprecated name.
   445→        factories().emplace(deprecated_name, &factory);
   446→        RELEASE_ASSERT(getFactory(deprecated_name) == &factory,
   447→                       "test factory registration by deprecated name failed");
   448→
   449→        // Register the replacement factory's deprecated name.
   450→        deprecatedFactoryNames().emplace(std::make_pair(deprecated_name, factory.name()));
   451→      }
   452→    }
   453→
   454→    rebuildFactoriesByTypeForTest();
   455→
   456→    return [replacement = &factory, prev_by_name, prev_deprecated_names]() {
   457→      // Unregister the replacement factory by name.
   458→      factories().erase(replacement->name());
   459→
   460→      ENVOY_LOG(info, "Removed test factory '{}' (type '{}')", replacement->name(),
   461→                replacement->configTypes());
   462→
   463→      if (prev_by_name) {
   464→        // Restore any factory displaced by name, but only register the type if it's non-empty.
   465→        factories().emplace(prev_by_name->name(), prev_by_name);
   466→
   467→        ENVOY_LOG(info, "Restored factory '{}' (type '{}'), formerly displaced-by-name",
   468→                  prev_by_name->name(), prev_by_name->configTypes());
   469→      }
   470→
   471→      for (auto [prev_deprecated_name, mapped_canonical_name] : prev_deprecated_names) {
   472→        deprecatedFactoryNames().erase(prev_deprecated_name);
   473→
   474→        ENVOY_LOG(info, "Removed deprecated name '{}'", prev_deprecated_name);
   475→
   476→        if (!mapped_canonical_name.empty()) {
   477→          deprecatedFactoryNames().emplace(
   478→              std::make_pair(prev_deprecated_name, mapped_canonical_name));
   479→
   480→          auto* deprecated_factory = getFactory(mapped_canonical_name);
   481→          RELEASE_ASSERT(deprecated_factory != nullptr,
   482→                         "failed to restore deprecated factory name");
   483→          factories().emplace(mapped_canonical_name, deprecated_factory);
   484→
   485→          ENVOY_LOG(info, "Restored deprecated name '{}' (mapped to '{}'", prev_deprecated_name,
   486→                    mapped_canonical_name);
   487→        }
   488→      }
   489→
   490→      rebuildFactoriesByTypeForTest();
   491→    };
   492→  }
   493→};
