 */
template <class ProtoMessage, class Factory>
static ProtobufTypes::MessagePtr
translateToFactoryConfig(const ProtoMessage& enclosing_message,
                         ProtobufMessage::ValidationVisitor& validation_visitor,
                         Factory& factory) {
